const activeId = ref<string>(
	(() => {
		const hash = window.location.hash?.slice(1);
		if (hash) return hash;

		/* <AUTO-GENERATED-DEFAULT-ID> */
return "ifx-accordion-example";
		/* </AUTO-GENERATED-DEFAULT-ID> */
	})(),
);

const getHashId = () => window.location.hash?.slice(1) ?? "";

const highlightCode = () => {
	nextTick(() => {
		Prism.highlightAll();
	});
};

const onHashChange = () => {
	const next = getHashId();
	if (next) {
		activeId.value = next;
	}
};

onMounted(() => {
	if (!getHashId()) {
		window.history.replaceState(null, "", `#${activeId.value}`);
	}

	window.addEventListener("hashchange", onHashChange);
	highlightCode();
});

onBeforeUnmount(() => {
	window.removeEventListener("hashchange", onHashChange);
});

watch(activeId, () => {
	highlightCode();
});
